const xml = $input.item.json.data || $input.item.json.body || '';
const crypto = require('crypto');
const entries = [];
const entryRegex = /<entry>([\s\S]*?)<\/entry>/g;
let match;
while ((match = entryRegex.exec(xml)) !== null) {
  const entry = match[1];
  const getTag = (tag) => {
    const m = entry.match(new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)</' + tag + '>', 's'));
    return m ? m[1].trim() : '';
  };
  const title = getTag('title').replace(/\s+/g, ' ');
  const abstract = getTag('summary').replace(/\s+/g, ' ').substring(0, 500);
  const published = getTag('published');
  const idTag = getTag('id');
  const arxivId = idTag.replace('http://arxiv.org/abs/', '');
  const authors = [];
  const authorRegex = /<author>\s*<name>([\s\S]*?)<\/name>/g;
  let am;
  while ((am = authorRegex.exec(entry)) !== null) authors.push(am[1].trim());
  const categories = [];
  const catRegex = /<category[^>]*term="([^"]+)"/g;
  let cm;
  while ((cm = catRegex.exec(entry)) !== null) categories.push(cm[1]);
  const content_hash = crypto.createHash('sha256')
    .update(arxivId.toLowerCase() + '|arxiv')
    .digest('hex');
  entries.push({
    json: {
      source: 'arxiv',
      source_category: 'paper',
      title: title,
      url: 'https://arxiv.org/abs/' + arxivId,
      raw_content: abstract,
      entities: [],
      metadata: { arxiv_id: arxivId, authors: authors, categories: categories, published: published },
      collected_at: published || new Date().toISOString(),
      content_hash: content_hash
    }
  });
}
return entries;
